import logging
import azure.functions as func
from azure.storage.blob import BlobServiceClient, BlobClient
import os

def main(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Python HTTP trigger function processed a request.')

    blob_path = req.params.get('blobPath')
    if not blob_path:
        return func.HttpResponse(
            "Please pass a blobPath on the query string",
            status_code=400
        )

    try:
        # Securely retrieve connection string from environment variables
        connect_str = os.getenv('AZURE_STORAGE_CONNECTION_STRING')
        if not connect_str:
            raise ValueError("Azure Storage connection string not found.")

        # Create a BlobServiceClient
        blob_service_client = BlobServiceClient.from_connection_string(connect_str)

        # Extract container name and blob name from the blob path
        container_name, blob_name = blob_path.split('/', 1)

        # Create a BlobClient
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)

        # Download the blob content
        blob_data = blob_client.download_blob().readall()

        return func.HttpResponse(
            blob_data,
            status_code=200,
            mimetype='application/octet-stream'
        )

    except Exception as e:
        logging.error(f"Error reading blob: {e}")
        return func.HttpResponse(
            "Error reading blob",
            status_code=500
        )